    29→		sql.SetMaxOpenConns(cfg.Database.MaxOpenConn)
    30→	}
    31→	if cfg.Database.ConnMaxLifetime > 0 {
    32→		sql.SetConnMaxLifetime(cfg.Database.ConnMaxLifetime)
    33→	}
    34→
    35→	registerMetrics(driver, sql)
    36→
    37→	return sql, driver, nil
    38→}
    39→
    40→type options struct {
    41→	sslDisabled bool
    42→	migrate     bool
    43→}
    44→
    45→func open(cfg config.Config, opts options) (*sql.DB, Driver, error) {
    46→	d, url, err := parse(cfg, opts)
    47→	if err != nil {
    48→		return nil, 0, err
    49→	}
    50→
    51→	driverName := fmt.Sprintf("instrumented-%s", d)
    52→
    53→	var (
    54→		dr    driver.Driver
    55→		attrs []attribute.KeyValue
    56→	)
    57→
    58→	switch d {
    59→	case SQLite:
    60→		dr = &sqlite3.SQLiteDriver{}
    61→		attrs = []attribute.KeyValue{semconv.DBSystemSqlite}
    62→	case Postgres:
    63→		dr = &pq.Driver{}
    64→		attrs = []attribute.KeyValue{semconv.DBSystemPostgreSQL}
    65→	case MySQL:
    66→		dr = &mysql.MySQLDriver{}
    67→		attrs = []attribute.KeyValue{semconv.DBSystemMySQL}
    68→	}
    69→
    70→	registered := false
    71→
    72→	for _, dd := range sql.Drivers() {
    73→		if dd == driverName {
    74→			registered = true
    75→			break
    76→		}
    77→	}
    78→
    79→	if !registered {
    80→		sql.Register(driverName, otelsql.WrapDriver(dr, otelsql.WithAttributes(attrs...)))
    81→	}
    82→
    83→	db, err := sql.Open(driverName, url.DSN)
    84→	if err != nil {
    85→		return nil, 0, fmt.Errorf("opening db for driver: %s %w", d, err)
    86→	}
    87→
    88→	return db, d, nil
    89→}
    90→
    91→var (
    92→	driverToString = map[Driver]string{
    93→		SQLite:   "sqlite3",
    94→		Postgres: "postgres",
    95→		MySQL:    "mysql",
    96→	}
    97→
    98→	stringToDriver = map[string]Driver{
    99→		"sqlite3":  SQLite,
   100→		"postgres": Postgres,
   101→		"mysql":    MySQL,
   102→	}
   103→)
   104→
   105→// Driver represents a database driver
   106→type Driver uint8
   107→
   108→func (d Driver) String() string {
   109→	return driverToString[d]
   110→}
   111→
   112→const (
   113→	_ Driver = iota
   114→	// SQLite ...
   115→	SQLite
   116→	// Postgres ...
   117→	Postgres
   118→	// MySQL ...
   119→	MySQL
   120→)
   121→
   122→func parse(cfg config.Config, opts options) (Driver, *dburl.URL, error) {
   123→	u := cfg.Database.URL
   124→
   125→	if u == "" {
   126→		host := cfg.Database.Host
   127→
   128→		if cfg.Database.Port > 0 {
   129→			host = fmt.Sprintf("%s:%d", host, cfg.Database.Port)
   130→		}
   131→
   132→		uu := url.URL{
   133→			Scheme: cfg.Database.Protocol.String(),
   134→			Host:   host,
   135→			Path:   cfg.Database.Name,
   136→		}
   137→
   138→		if cfg.Database.User != "" {
   139→			if cfg.Database.Password != "" {
   140→				uu.User = url.UserPassword(cfg.Database.User, cfg.Database.Password)
   141→			} else {
   142→				uu.User = url.User(cfg.Database.User)
   143→			}
   144→		}
   145→
   146→		u = uu.String()
   147→	}
   148→
   149→	url, err := dburl.Parse(u)
   150→	if err != nil {
   151→		return 0, nil, fmt.Errorf("error parsing url: %q, %w", url, err)
   152→	}
   153→
   154→	driver := stringToDriver[url.Driver]
   155→	if driver == 0 {
   156→		return 0, nil, fmt.Errorf("unknown database driver for: %q", url.Driver)
   157→	}
   158→
   159→	switch driver {
   160→	case Postgres:
   161→		if opts.sslDisabled {
   162→			v := url.Query()
   163→			v.Set("sslmode", "disable")
   164→			url.RawQuery = v.Encode()
   165→			// we need to re-parse since we modified the query params
   166→			url, err = dburl.Parse(url.URL.String())
   167→		}
   168→	case MySQL:
   169→		v := url.Query()
   170→		v.Set("multiStatements", "true")
   171→		v.Set("parseTime", "true")
   172→		if !opts.migrate {
   173→			v.Set("sql_mode", "ANSI")
   174→		}
   175→		url.RawQuery = v.Encode()
   176→		// we need to re-parse since we modified the query params
   177→		url, err = dburl.Parse(url.URL.String())
   178→
   179→	case SQLite:
   180→		v := url.Query()
   181→		v.Set("cache", "shared")
   182→		v.Set("_fk", "true")
   183→		url.RawQuery = v.Encode()
   184→
   185→		// we need to re-parse since we modified the query params
   186→		url, err = dburl.Parse(url.URL.String())
   187→	}
   188→
   189→	return driver, url, err
   190→}
